import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 施無畏印, 與願印, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛舞 = (bi) => 菩薩坐身(bi, {
    髻: '天髻',
    冠: '無',
    臂(bi, 筆) {
        const { 骨, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
        // 尊右：掌開當胸（舞之揚掌）
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-5.9, 37.3], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        施無畏印(bi, -4.6, 33.2, 0.62, false);
        // 尊左：掌開添於腰際（舞之按掌）
        骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [12.4, 44.8], { 寬根: 2.4, 寬梢: 1.8, 弓: -0.3, 肘帽: false })));
        與願印(bi, 12.0, 48.6, 0.62, false);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-6.9, 36.4, -6.2, 37.3, -5.5, 38.1], [-6.4, 35.8, -5.7, 36.7, -5.0, 37.5]], [-6.0, 36.8]);
            腕釧(bi, [[11.3, 44.4, 12.4, 44.9, 13.5, 44.5], [11.2, 45.3, 12.3, 45.8, 13.4, 45.4]], [12.3, 45.3]);
        });
    },
});
